mapper.select:
SELECT *
FROM cabinet_slot
WHERE cabinet_id = #{cabinetId}
  AND slot_no = #{slotNo}
  AND deleted = 0
LIMIT 1

SELECT COUNT(1)
FROM cabinet_slot
WHERE cabinet_id = #{cabinetId}
  AND slot_no = #{slotNo}
  AND deleted = 0

  AND id != #{excludeId}

SELECT COUNT(1)
FROM cabinet_slot
WHERE item_id = #{itemId}
  AND deleted = 0

  AND id != #{excludeId}

mapper.update:
UPDATE cabinet_slot
SET item_quantity = item_quantity - #{quantity}
WHERE id = #{slotId}
  AND deleted = 0
  AND COALESCE(item_quantity, 0) >= #{quantity}

UPDATE cabinet_slot
SET item_quantity = COALESCE(item_quantity, 0) + #{quantity}
WHERE id = #{slotId}
  AND deleted = 0
